{
  "grammar": [
    {
      "pattern": "身體部位 + 痛",
      "structure": ["身體部位", "痛"],
      "explanation_en": "Use this pattern to say a body part hurts. Place the body part before 痛.",
      "title": "Saying a Body Part Hurts",
      "meaning": "Body part hurts",
      "when_to_use": ["When describing physical pain", "When telling a doctor or friend where it hurts"],
      "when_not_to_use": ["For emotional pain", "For general discomfort without a specific body part"],
      "pragmatic_notes": "In Taiwan, people often say 頭痛, 肚子痛, 喉嚨痛. You can add 很 before 痛 to emphasize severity.",
      "word_order_notes": "Body part always comes before 痛, like 頭 + 痛 = 頭痛.",
      "english_contrast": "In English, you say 'My head hurts' or 'I have a headache'. In Chinese, just say 頭痛 without 'my'.",
      "korean_contrast": "In Korean, you say '머리가 아파요' (head + subject marker + hurts). Chinese is simpler: just 頭痛.",
      "negative_examples": [
        {
          "text": "痛頭",
          "error": "Word order is wrong. Body part must come before 痛."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我痛頭",
          "error": "You don't need 我. Just say 頭痛."
        }
      ],
      "transformation_drills": ["Change 頭痛 to 肚子痛", "Change 喉嚨痛 to 牙齒痛"],
      "production_drills": ["Say 'My stomach hurts' in Chinese", "Say 'My back hurts' in Chinese"],
      "common_error_patterns": ["Putting 痛 before the body part", "Adding 我 unnecessarily"],
      "repair_feedback": {
        "word_order": "Put the body part first, then 痛.",
        "politeness": "This pattern is neutral and polite.",
        "vocabulary": "Use body part words like 頭, 肚子, 喉嚨."
      }
    },
    {
      "pattern": "有點 + 症狀",
      "structure": ["有點", "症狀"],
      "explanation_en": "Use 有點 to say you have a mild symptom. It softens the statement.",
      "title": "Expressing Mild Symptoms",
      "meaning": "A little bit of symptom",
      "when_to_use": ["When symptoms are not severe", "When you want to sound polite or modest"],
      "when_not_to_use": ["For severe or serious symptoms", "For positive feelings"],
      "pragmatic_notes": "In Taiwan, 有點 is common in daily conversation. For example, 有點咳嗽 means 'a little cough'.",
      "word_order_notes": "有點 comes before the symptom word, like 有點 + 頭痛.",
      "english_contrast": "In English, you say 'I have a bit of a headache'. In Chinese, say 有點頭痛.",
      "korean_contrast": "In Korean, you say '머리가 조금 아파요' (head + a little + hurts). Chinese uses 有點 + symptom.",
      "negative_examples": [
        {
          "text": "頭痛有點",
          "error": "有點 must come before the symptom."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我有點很頭痛",
          "error": "Don't use 很 with 有點. 有點 already means 'a little'."
        }
      ],
      "transformation_drills": ["Change 有點頭痛 to 有點肚子痛", "Change 有點咳嗽 to 有點流鼻水"],
      "production_drills": ["Say 'I have a little fever' in Chinese", "Say 'I feel a bit dizzy' in Chinese"],
      "common_error_patterns": ["Putting 有點 after the symptom", "Adding 很 after 有點"],
      "repair_feedback": {
        "word_order": "Put 有點 before the symptom.",
        "politeness": "Using 有點 makes you sound polite and not complaining too much.",
        "vocabulary": "Use symptom words like 頭痛, 咳嗽, 發燒."
      }
    },
    {
      "pattern": "從 + 時間 + 開始 + 症狀 + 到現在",
      "structure": ["從", "時間", "開始", "症狀", "到現在"],
      "explanation_en": "Use this pattern to say when a symptom started and that it continues until now.",
      "title": "Saying How Long a Symptom Has Lasted",
      "meaning": "Symptom started at time and continues to now",
      "when_to_use": ["When telling a doctor when symptoms began", "When describing ongoing symptoms"],
      "when_not_to_use": ["For symptoms that have already ended", "Without specifying a start time"],
      "pragmatic_notes": "In Taiwan, you can say 從昨天開始頭痛到現在 to mean 'headache from yesterday until now'.",
      "word_order_notes": "Start with 從, then time, then 開始, then symptom, then 到現在.",
      "english_contrast": "In English, you say 'I've had a headache since yesterday'. In Chinese, say 從昨天開始頭痛到現在.",
      "korean_contrast": "In Korean, you say '어제부터 지금까지 머리가 아파요' (from yesterday to now head hurts). Chinese structure is similar but uses 開始.",
      "negative_examples": [
        {
          "text": "頭痛從昨天開始到現在",
          "error": "Symptom should come after 開始, not at the beginning."
        }
      ],
      "incorrect_examples": [
        {
          "text": "從昨天頭痛開始到現在",
          "error": "時間 must come right after 從, not the symptom."
        }
      ],
      "transformation_drills": ["Change 從昨天開始頭痛到現在 to 從早上開始咳嗽到現在", "Change 從前天開始發燒到現在 to 從今天開始肚子痛到現在"],
      "production_drills": ["Say 'My throat has hurt since this morning' in Chinese", "Say 'I've had a fever since yesterday' in Chinese"],
      "common_error_patterns": ["Putting symptom before 從", "Omitting 開始 or 到現在"],
      "repair_feedback": {
        "word_order": "Follow the order: 從 + time + 開始 + symptom + 到現在.",
        "politeness": "This pattern is clear and polite for medical contexts.",
        "vocabulary": "Use time words like 昨天, 早上, 前天."
      }
    }
  ]
}
